window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["cdl-hazmat"] = window.COURSE_LANG["cdl-hazmat"] || {};
window.COURSE_LANG["cdl-hazmat"]["es"] = [
  {"id":1,"q":"Los materiales peligrosos son productos que pueden representar un riesgo para:","opts":["La salud, la seguridad y la propiedad durante el transporte","Solo el conductor","Solo el motor del camión","Nada si están empacados"],"re":"El hazmat puede poner en peligro la salud, la seguridad y la propiedad durante el transporte."},
  {"id":2,"q":"Para transportar cantidades con placard de materiales peligrosos, el conductor necesita:","opts":["Nada adicional","Un endoso de Hazmat (H) con verificación de antecedentes de la TSA","Un endoso de pasajeros","Un endoso de dobles/triples"],"re":"El endoso de Hazmat (H) requiere aprobar una verificación de antecedentes de la TSA."},
  {"id":3,"q":"¿Cuántas clases de peligro existen?","opts":["3","6","9","12"],"re":"Existen 9 clases de peligro, desde explosivos hasta misceláneos."},
  {"id":4,"q":"¿Qué número de clase de peligro corresponde a los explosivos?","opts":["Clase 3","Clase 7","Clase 1","Clase 8"],"re":"La Clase 1 son los explosivos."},
  {"id":5,"q":"¿En qué clase de peligro entran los líquidos inflamables?","opts":["Clase 1","Clase 6","Clase 9","Clase 3"],"re":"La Clase 3 son los líquidos inflamables."},
  {"id":6,"q":"¿Qué parte es responsable de empacar, etiquetar y certificar el hazmat?","opts":["El expedidor (shipper)","El conductor","El mecánico","El despachador"],"re":"El expedidor empaca, etiqueta, certifica y prepara los documentos de embarque."},
  {"id":7,"q":"¿De quién es la tarea de colocar y mantener los placards en el vehículo?","opts":["El expedidor","El conductor","La fábrica","El destinatario"],"re":"El conductor coloca y mantiene los placards y conserva los documentos accesibles."},
  {"id":8,"q":"El documento que indica cómo debe transportarse cada material es:","opts":["La bitácora del conductor","El manual del propietario","La Tabla de Materiales Peligrosos","El recibo de combustible"],"re":"La Tabla de Materiales Peligrosos indica cómo transportar cada material listado."},
  {"id":9,"q":"Los materiales peligrosos de Clase 8 son:","opts":["Gases","Radiactivos","Explosivos","Corrosivos"],"re":"La Clase 8 son corrosivos, como los ácidos fuertes."},
  {"id":10,"q":"Los documentos de embarque deben describir cada hazmat por nombre de embarque correcto, clase de peligro y:","opts":["El número de identificación (UN/NA)","El nombre del conductor","El color del camión","El clima"],"re":"Los documentos listan el nombre de embarque, la clase de peligro y el número de identificación (UN/NA), más el grupo de embalaje."},
  {"id":11,"q":"Mientras se conduce, los documentos de embarque del hazmat deben estar:","opts":["Encerrados en el remolque","Al alcance del conductor y fáciles de hallar","Enviados a la oficina","Dejados en la terminal"],"re":"Los documentos deben estar al alcance al conducir y ser fáciles de hallar para otros."},
  {"id":12,"q":"Cuando el conductor sale del camión, los documentos de embarque deben quedar:","opts":["Escondidos bajo el capó","Solo en la guantera","En una bolsa en la puerta del conductor o sobre el asiento","Tirados a la basura"],"re":"Deja los documentos en la bolsa de la puerta del conductor o sobre el asiento para hallarlos fácil."},
  {"id":13,"q":"Las anotaciones de hazmat en un documento de embarque mixto deben estar:","opts":["Escritas solo a lápiz","Omitidas de la página","Impresas en otro idioma","Resaltadas, con pestaña o listadas primero para que destaquen"],"re":"El hazmat debe ser fácil de hallar: con pestaña, resaltado o listado antes de lo que no es hazmat."},
  {"id":14,"q":"El número de identificación en un paquete se marca como:","opts":["Un número UN o NA","Solo un código de color","Solo un código de barras","Las iniciales del conductor"],"re":"El número de identificación se muestra como un número UN o NA en el paquete y los documentos."},
  {"id":15,"q":"Un paquete marcado como CONTAMINANTE MARINO (MARINE POLLUTANT) indica que el contenido puede:","opts":["Flotar para siempre","Dañar la vida acuática si se derrama","Nunca tener fugas","Comerse sin riesgo"],"re":"La marca de CONTAMINANTE MARINO advierte que el material puede dañar la vida acuática."},
  {"id":16,"q":"La palabra HOT (CALIENTE) marcada en un contenedor significa que el material:","opts":["Es picante","Está frío","Se transporta a alta temperatura","Está congelado"],"re":"HOT marca materiales transportados a temperatura elevada."},
  {"id":17,"q":"La certificación del expedidor en los documentos significa que el expedidor:","opts":["Ha manejado la ruta","Ha comprado el camión","Ha revisado las llantas","Preparó el embarque conforme a las normas"],"re":"El expedidor firma para certificar que el embarque se preparó según las reglas."},
  {"id":18,"q":"Los placards son señales de advertencia con forma de:","opts":["Diamante (cuadrado sobre una punta)","Círculo","Cuadrado apoyado plano","Triángulo"],"re":"Los placards tienen forma de diamante (un cuadrado girado sobre su punta)."},
  {"id":19,"q":"En una carga con placard, los placards deben colocarse en:","opts":["Solo el frente","Los cuatro lados del vehículo","Solo la parte trasera","Solo un lado"],"re":"Los placards van en los cuatro lados para que el peligro se vea desde cualquier dirección."},
  {"id":20,"q":"La mayoría de las cargas necesita placards cuando se transporta al menos:","opts":["10 libras","50 libras","500 libras","1,001 libras de material que requiere placard"],"re":"La mayoría de los materiales con placard requiere placards a partir de 1,001 libras."},
  {"id":21,"q":"Debes colocar los placards requeridos:","opts":["Después de la primera parada","Solo en la báscula","Antes de conducir","En el punto de entrega"],"re":"Coloca los placards antes de conducir; nunca muevas una carga mal señalizada con placard."},
  {"id":22,"q":"Algunos materiales de la Tabla 1 deben llevar placard:","opts":["Solo sobre 5,000 libras","Solo cuando hay fuga","Nunca","En cualquier cantidad"],"re":"Ciertos materiales de la Tabla 1 requieren placards en cualquier cantidad, incluso pequeña."},
  {"id":23,"q":"Si te falta el placard correcto, debes:","opts":["No mover la carga hasta que tenga el placard correcto","Conducir con cuidado de todos modos","Cubrir la carga","Usar cualquier placard que tengas"],"re":"Nunca muevas una carga mal señalizada; consigue primero los placards correctos."},
  {"id":24,"q":"Los placards ayudan principalmente al:","opts":["Decorar el camión","Advertir a otros de la clase de peligro que se transporta","Ahorrar combustible","Reemplazar los documentos de embarque"],"re":"Los placards advierten al público y a los rescatistas sobre la clase de peligro a bordo."},
  {"id":25,"q":"El número que aparece en la esquina inferior de un placard suele indicar:","opts":["El peso del camión","La edad del conductor","La clase o división de peligro","El límite de velocidad"],"re":"El número inferior del placard indica la clase o división de peligro."},
  {"id":26,"q":"Un placard estándar mide al menos:","opts":["3 pulgadas por lado","5 pulgadas por lado","10.75 pulgadas por lado","24 pulgadas por lado"],"re":"Los placards miden al menos 10.75 pulgadas por lado para verse con claridad."},
  {"id":27,"q":"Al cargar hazmat, los paquetes deben:","opts":["Apilarse sueltos","Dejarse deslizar","Ponerse en el parachoques","Asegurarse para que no se muevan"],"re":"Asegura y traba los paquetes para que no se desplacen, caigan ni se dañen."},
  {"id":28,"q":"No se permite fumar al cargar o descargar cerca de:","opts":["Explosivos, oxidantes o inflamables","Tarimas vacías","Agua simple","Llantas de repuesto"],"re":"Nunca fumes cerca de explosivos, oxidantes o materiales inflamables."},
  {"id":29,"q":"Para decidir qué materiales pueden cargarse juntos, usas la:","opts":["Reporte del clima","Tabla de segregación (separación)","Bitácora de combustible","Tabla de llantas"],"re":"La tabla de segregación muestra qué materiales deben mantenerse separados."},
  {"id":30,"q":"Algunos materiales peligrosos:","opts":["Siempre son seguros juntos","No necesitan separación","Nunca pueden cargarse juntos","Pueden mezclarse libremente"],"re":"Ciertos materiales son incompatibles y no pueden cargarse juntos de ninguna manera."},
  {"id":31,"q":"Antes de cargar hazmat en un tanque o remolque, debes verificar que el:","opts":["Radio funcione","Los asientos estén limpios","Los espejos estén polarizados","Contenedor sea del tipo correcto y sin daños para el material"],"re":"Usa el contenedor correcto, sin daños y aprobado para ese material."},
  {"id":32,"q":"Las herramientas usadas para cargar o asegurar hazmat deben ser:","opts":["Elegidas para que no dañen los paquetes ni generen chispas","De cualquier material","Lo más pesadas posible","Dejadas sobre la carga"],"re":"Usa herramientas y material de estiba que no perforen paquetes ni generen chispas."},
  {"id":33,"q":"Los contenedores de materiales peligrosos deben cargarse de modo que queden:","opts":["Boca abajo","Verticales con los cierres hacia arriba, como se indica","Solo de costado","Abiertos para que entre aire"],"re":"Carga los contenedores derechos con los cierres hacia arriba, salvo que se marque otra cosa."},
  {"id":34,"q":"Después de cargar explosivos, debes asegurarte de que no haya:","opts":["Mapas en la cabina","Trapos limpios","Herramientas filosas o chispas que puedan detonarlos","Fusibles de repuesto para las luces"],"re":"Mantén chispas, llamas y objetos filosos lejos de los explosivos durante la carga."},
  {"id":35,"q":"Una carga con placard debe detenerse antes de un cruce de ferrocarril a:","opts":["Solo en la pluma del cruce","Justo sobre las vías","100 yardas de distancia","Entre 15 y 50 pies del riel más cercano"],"re":"Detente de 15 a 50 pies antes del riel más cercano y no cambies de marcha al cruzar."},
  {"id":36,"q":"Al cruzar las vías del ferrocarril con una carga con placard, debes:","opts":["No cambiar de marcha durante el cruce","Cambiar a una marcha más alta","Detenerte sobre las vías","Acelerar bruscamente"],"re":"No cambies de marcha sobre las vías para no calarte."},
  {"id":37,"q":"Durante un viaje con hazmat debes inspeccionar las llantas:","opts":["Solo antes de la primera milla","Al inicio y en cada parada, revisando las llantas duales","Nunca","Solo si una está desinflada"],"re":"Revisa las llantas antes del viaje y en cada parada, incluidas las llantas duales."},
  {"id":38,"q":"Al estacionar un vehículo con placard, debes mantenerlo al menos a:","opts":["1 pie de la carretera","5 pies de la parte transitada de la carretera","Tocando la cuneta","Sobre la línea del acotamiento"],"re":"No estaciones a menos de 5 pies de la parte transitada de la carretera."},
  {"id":39,"q":"¿A qué distancia mínima de un fuego abierto debe estacionarse un vehículo con placard?","opts":["10 pies","50 pies","100 pies","300 pies"],"re":"Mantén una carga con placard al menos a 300 pies de cualquier fuego abierto."},
  {"id":40,"q":"Cerca de una carga de hazmat debes evitar:","opts":["Usar los espejos","Señalar las vueltas","Llamas abiertas y cigarrillos encendidos","Usar guantes"],"re":"Mantén las llamas abiertas y los cigarrillos lejos de una carga de hazmat."},
  {"id":41,"q":"Ciertas cargas de hazmat tienen restringido el paso por algunos:","opts":["Áreas de descanso","Estacionamientos","Paradas de combustible","Túneles y rutas específicas"],"re":"Algunos túneles y rutas están prohibidos para ciertas cargas peligrosas; sigue los letreros."},
  {"id":42,"q":"Cuando una carga requiere vigilancia, el conductor debe:","opts":["Quedarse con ella o que una persona calificada la vigile","Dejarla sin vigilancia toda la noche","Estacionarla e irse a casa","Cerrarla con llave y alejarse"],"re":"Los materiales que requieren vigilancia exigen que el conductor o una persona calificada esté cerca."},
  {"id":43,"q":"El libro que da guía de primera respuesta para un incidente de hazmat es la:","opts":["Directorio telefónico","Guía de Respuesta a Emergencias (ERG)","Manual del propietario del camión","Atlas de carreteras"],"re":"La Guía de Respuesta a Emergencias (ERG) lista los peligros y los primeros pasos de respuesta."},
  {"id":44,"q":"Si el hazmat tiene una fuga, lo que NO debes hacer es:","opts":["Mantener a la gente alejada","Advertir a otros","Mover el vehículo a donde puedas hallar ayuda y dejar que siga goteando","Pedir ayuda"],"re":"No conduzcas un vehículo con fuga más de lo que exija la seguridad; no dejes que siga esparciéndose."},
  {"id":45,"q":"Ante un derrame de hazmat, una de tus primeras acciones es:","opts":["Lavarlo hacia un drenaje","Encender una bengala en el derrame","Probar el material","Mantener a la gente alejada y evitar que fumen"],"re":"Mantén a la gente atrás, evita que fumen y enciendan fuego, y advierte del peligro a otros."},
  {"id":46,"q":"Tras una fuga o derrame de hazmat, debes:","opts":["Notificar a las autoridades correspondientes","No decir nada","Esconder los documentos","Continuar la ruta"],"re":"Reporta las fugas y derrames a las autoridades correspondientes según se requiera."},
  {"id":47,"q":"Si puedes hacerlo con seguridad ante un derrame, debes tratar de:","opts":["Ignorarlo","Contener el material para limitar su esparcimiento","Esparcirlo","Enterrarlo rápido"],"re":"Contén la fuga si es seguro hacerlo, para limitar hasta dónde se esparce."},
  {"id":48,"q":"Para protegerse contra la manipulación indebida, un conductor de hazmat debe:","opts":["Dejar el camión sin seguro","Compartir la ruta con muchos","Ignorar a los extraños cerca del camión","Estar alerta y revisar la carga por señales de manipulación"],"re":"Vigila la manipulación indebida y sigue el plan de seguridad para mantener la carga segura."},
  {"id":49,"q":"Un plan de seguridad de hazmat busca:","opts":["Reducir el riesgo de robo o mal uso de los materiales","Aumentar el rendimiento de combustible","Decorar el remolque","Reemplazar los frenos"],"re":"El plan de seguridad reduce el riesgo de que el hazmat sea robado o usado para causar daño."},
  {"id":50,"q":"Antes de aceptar un embarque de hazmat, el conductor debe:","opts":["Saltarse todas las revisiones","Verificar al expedidor y que la carga coincida con los documentos","Quitar los placards","Borrar los números de identificación"],"re":"Verifica al expedidor y confirma que la carga coincida con los documentos de embarque."}
];
